    sigma_KLWU += 1/8 * einsum('Kxyz,Lwux,UWuwzy->KLWU', X_aaaa, v_vaaa, rdm_cccaaa, optimize = einsum_type)
    sigma_KLWU += 1/24 * einsum('Kxyz,Lwux,UWuzwy->KLWU', X_aaaa, v_vaaa, rdm_cccaaa, optimize = einsum_type)
    sigma_KLWU -= 1/24 * einsum('Kxyz,Lwux,UWuzyw->KLWU', X_aaaa, v_vaaa, rdm_cccaaa, optimize = einsum_type)
    sigma_KLWU -= 1/3 * einsum('Kxyz,LwyW,Uxwz->KLWU', X_aaaa, v_vaaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLWU -= 1/6 * einsum('Kxyz,LwyW,Uxzw->KLWU', X_aaaa, v_vaaa, rdm_ccaa, optimize = einsum_type)
