    sigma_KLCW_abab -= 1/6 * einsum('Kxyz,LwuC,Wuvy,xwzv->KLCW', X_aaaa, t1_vaae, v_aaaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLCW_abab -= 1/6 * einsum('Kxyz,LwuC,Wuxv,yzvw->KLCW', X_aaaa, t1_vaae, v_aaaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLCW_abab += 1/6 * einsum('Kxyz,LwuC,Wvwy,xvuz->KLCW', X_aaaa, t1_vaae, v_aaaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLCW_abab += 1/3 * einsum('Kxyz,LwuC,Wvwy,xvzu->KLCW', X_aaaa, t1_vaae, v_aaaa, rdm_ccaa, optimize = einsum_type)
    sigma_KLCW_abab += 1/8 * einsum('Kxyz,LwuC,xvsu,Wwvszy->KLCW', X_aaaa, t1_vaae, v_aaaa, rdm_cccaaa, optimize = einsum_type)
