    sigma_KLCW_abab -= 1/24 * einsum('Kxyz,LwuC,xvsu,Wwvzys->KLCW', X_aaaa, t1_vaae, v_aaaa, rdm_cccaaa, optimize = einsum_type)
    sigma_KLCW_abab += 1/8 * einsum('Kxyz,LwuC,xvws,Wvsuzy->KLCW', X_aaaa, t1_vaae, v_aaaa, rdm_cccaaa, optimize = einsum_type)
    sigma_KLCW_abab += 1/24 * einsum('Kxyz,LwuC,xvws,Wvszuy->KLCW', X_aaaa, t1_vaae, v_aaaa, rdm_cccaaa, optimize = einsum_type)
